—{r}
library(dslabs)
data(“polls_us_election_2016”)
data &lt;- polls_us_election_2016
my_first &lt;- “Mehmet”
my_birth_year &lt;- 2004
k &lt;- (nchar(my_first) + my_birth_year) %% 15 + 8
if (k %% 2 == 0) { print(head(data, k)) } else { print(tail(data, k)) }
total_na &lt;- sum(is.na(data)) print(paste(“Toplam NA sayısı:”, total_na,“”))
na_per_column &lt;- sort(colSums(is.na(data)), decreasing = TRUE) print(“En çok NA içeren ilk 8 sütun:”) print(head(na_per_column, 8))
new_data &lt;- data
num_fill &lt;- my_birth_year + k
char_fill &lt;- paste0(my_first, k)

for(col_name in names(new_data)) {
if(is.numeric(new_data[[col_name]])) {
new_data[[col_name]][is.na(new_data[[col_name]])] &lt;- num_fill } else {
new_data[[col_name]][is.na(new_data[[col_name]])] &lt;- char_fill }
}
if (k %% 2 == 0) {
print(head(new_data, k))
} else {
print(tail(new_data, k))
}
print(paste(“Yeni veri setindeki toplam NA:”, sum(is.na(new_data))))
print(anyNA(new_data))
